/* Coordonnées (lat, lng) des villes marocaines principales, utilisées pour calculer
   une vraie distance entre la position réelle de l'utilisateur et les annonces.
   Complète cette liste si de nouvelles villes sont utilisées dans tes annonces. */
const CITY_COORDS = {
  "Casablanca": [33.5731, -7.5898], "Rabat": [34.0209, -6.8416], "Marrakech": [31.6295, -7.9811],
  "Fès": [34.0331, -5.0003], "Tanger": [35.7595, -5.8340], "Agadir": [30.4278, -9.5981],
  "Meknès": [33.8935, -5.5473], "Oujda": [34.6805, -1.9086], "Kénitra": [34.2610, -6.5802],
  "Tétouan": [35.5785, -5.3684], "Salé": [34.0531, -6.7985], "Essaouira": [31.5085, -9.7595],
  "El Jadida": [33.2316, -8.5007], "Nador": [35.1681, -2.9287], "Béni Mellal": [32.3373, -6.3498],
  "Safi": [32.2994, -9.2372], "Khouribga": [32.8811, -6.9063], "Settat": [33.0010, -7.6166],
  "Paris": [48.8566, 2.3522], "Lyon": [45.7640, 4.8357], "Marseille": [43.2965, 5.3698],
};

// Distance réelle en km entre deux points GPS (formule de Haversine)
function distanceKm([lat1, lng1], [lat2, lng2]) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// Demande la vraie position GPS/réseau de l'utilisateur au navigateur (avec sa permission).
// Ne renvoie jamais de fausse localisation : si la permission est refusée ou indisponible,
// coords reste null et l'appelant doit gérer cet état honnêtement (pas de valeur par défaut inventée).
function useRealGeolocation() {
  const [coords, setCoords] = useState(null);
  const [status, setStatus] = useState("idle"); // idle | loading | granted | denied | unsupported

  useEffect(() => {
    if (!("geolocation" in navigator)) { setStatus("unsupported"); return; }
    setStatus("loading");
    navigator.geolocation.getCurrentPosition(
      (pos) => { setCoords([pos.coords.latitude, pos.coords.longitude]); setStatus("granted"); },
      () => setStatus("denied"),
      { enableHighAccuracy: false, timeout: 8000, maximumAge: 5 * 60 * 1000 }
    );
  }, []);

  return { coords, status };
}

