const LANG_KEY = "secondiy_lang";
function useLang() {
  const [lang, setLangState] = useState(() => localStorage.getItem(LANG_KEY) || "fr");
  const setLang = (l) => { localStorage.setItem(LANG_KEY, l); setLangState(l); };
  const t = (key) => TRANSLATIONS[lang]?.[key] ?? TRANSLATIONS.fr[key] ?? key;
  return { lang, setLang, t };
}

// Upload réel d'une image vers Cloudinary (stockage cloud gratuit).
// Configuré via VITE_CLOUDINARY_CLOUD_NAME et VITE_CLOUDINARY_UPLOAD_PRESET (voir .env.production).
async function uploadImageToCloudinary(file) {
  const cloudName = import.meta.env.VITE_CLOUDINARY_CLOUD_NAME;
  const preset = import.meta.env.VITE_CLOUDINARY_UPLOAD_PRESET;
  if (!cloudName || !preset) {
    throw new Error("L'upload de photos n'est pas encore configuré (Cloudinary manquant).");
  }
  const form = new FormData();
  form.append("file", file);
  form.append("upload_preset", preset);
  const res = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, { method: "POST", body: form });
  if (!res.ok) throw new Error("Échec de l'envoi de la photo.");
  const data = await res.json();
  return data.secure_url;
}

/* Logo officiel SeconDIY — monogramme découpé et détouré à partir du fichier fourni.
   Deux variantes : bordeaux (sur fond clair) et crème (sur fond sombre). */
const LOGO_ICON_DARK = "data:image/png;base64,";  // monogramme bordeaux — à poser sur fond clair
const LOGO_ICON_LIGHT = "data:image/png;base64,"; // monogramme crème — à poser sur fond sombre


/* ==========================================================================
   SECONDIY — v2
   Direction : Vinted (grille produit dense, confiance) × Instagram (profils,
   grid, feed) × app de luxe (typographie du prix, espace, micro-interactions).
   Palette reprise du logo SeconDIY : crème + bordeaux profond.
   Tokens couleur pilotés par variables CSS --bg/--surface/--text/--accent/--accent2
   pour supporter le dark mode instantané sans dupliquer les classes.
   Signature : le pictogramme cintre + feuille du logo (Achète · Vends · Transforme),
   réutilisé comme spinner de chargement IA partout dans l'app.
========================================================================== */

const PLACEHOLDERS = [
  "Je cherche une robe Zara à 200 DH…",
  "Un iPhone pas cher à Casablanca…",
  "Une veste en cuir taille M…",
  "Des sneakers blanches, budget 400 DH…",
];

function itemIcon(p) {
  const t = (p?.title || "").toLowerCase();
  if (t.includes("sneaker") || t.includes("nike") || t.includes("balance")) return Footprints;
  if (t.includes("sac")) return ShoppingBag;
  if (t.includes("iphone") || t.includes("phone")) return Smartphone;
  if (t.includes("robe") || t.includes("veste") || t.includes("jean")) return Shirt;
  if (t.includes("fauteuil") || t.includes("table")) return Sofa;
  if (t.includes("lampe")) return Lamp;
  if (t.includes("montre")) return Watch;
  return ShoppingBag;
}

