/* ---------------- smart search ---------------- */
function AISearchBar({ big, compact }) {
  const [q, setQ] = useState("");
  const [ph, setPh] = useState(0);
  const [thinking, setThinking] = useState(false);
  const [result, setResult] = useState(null);

  useEffect(() => {
    const t = setInterval(() => setPh(p => (p + 1) % PLACEHOLDERS.length), 2600);
    return () => clearInterval(t);
  }, []);

  const run = () => {
    if (!q.trim()) return;
    setThinking(true); setResult(null);
    setTimeout(() => { setThinking(false); setResult(q); }, 850);
  };

  return (
    <div className={`w-full ${big ? "max-w-xl" : compact ? "max-w-xs" : "max-w-md"} mx-auto`}>
      <div className={`flex items-center gap-2 bg-[var(--surface)] rounded-full border border-[var(--border)] ${compact ? "shadow-none pl-3.5 pr-1 py-1" : "shadow-lg shadow-black/5 pl-5 pr-1.5 py-1.5"} focus-within:border-[var(--accent)] focus-within:shadow-[var(--accent)]/10 transition-all duration-300`}>
        <Search size={compact ? 14 : 17} className="text-[var(--accent)] shrink-0" />
        <div className={`relative flex-1 ${compact ? "h-5" : "h-6"}`}>
          <input
            value={q} onChange={e => setQ(e.target.value)} onKeyDown={e => e.key === "Enter" && run()}
            className={`absolute inset-0 w-full bg-transparent outline-none text-[var(--text)] py-0 ${compact ? "text-[12.5px]" : "text-[14.5px]"}`}
          />
          {!q && (
            <span key={ph} className={`absolute inset-0 flex items-center text-[var(--text-dim)]/50 pointer-events-none animate-fade-swap truncate ${compact ? "text-[12px]" : "text-[14.5px]"}`}>
              {PLACEHOLDERS[ph]}
            </span>
          )}
        </div>
        <button onClick={run}
          className={`shrink-0 rounded-full bg-[var(--accent)] text-white grid place-items-center hover:brightness-110 transition-colors active:scale-90 ${compact ? "w-7 h-7" : "w-10 h-10"}`}>
          {thinking ? <CycleMark size={compact ? 12 : 16} spin /> : <Search size={compact ? 12 : 16} />}
        </button>
      </div>
      {result && !thinking && !compact && (
        <p className="text-center text-[12.5px] text-[var(--text-dim)] mt-2.5 animate-fade-in">
          Compris ✨ — je cherche <span className="text-[var(--accent)]">« {result} »</span>
        </p>
      )}
    </div>
  );
}

