// Préférences de notification : stockées localement sur cet appareil (pas encore d'envoi
// d'e-mails/push réel côté serveur, donc on ne prétend pas plus que ce que ça fait vraiment).
function NotificationsSection() {
  const KEY = "secondiy_notif_prefs";
  const defaults = { messages: true, favoris: true, matches: true, promos: false };
  const [prefs, setPrefs] = useState(() => {
    try { return { ...defaults, ...JSON.parse(localStorage.getItem(KEY) || "{}") }; } catch { return defaults; }
  });
  const toggle = (k) => setPrefs(p => { const next = { ...p, [k]: !p[k] }; localStorage.setItem(KEY, JSON.stringify(next)); return next; });

  const items = [
    ["messages", "Nouveaux messages"],
    ["favoris", "Activité sur mes favoris"],
    ["matches", "Nouveaux articles qui correspondent à mes recherches"],
    ["promos", "Promotions et offres SeconDIY"],
  ];
  return (
    <div className="max-w-lg space-y-1">
      <p className="text-[12.5px] text-[var(--text-dim)] mb-4">Ces préférences sont enregistrées sur cet appareil.</p>
      {items.map(([k, l]) => (
        <div key={k} className="flex items-center justify-between py-3 border-b border-[var(--border)]">
          <span className="text-[13.5px] text-[var(--text)]">{l}</span>
          <button onClick={() => toggle(k)} className={`w-11 h-6 rounded-full transition-colors relative ${prefs[k] ? "bg-[var(--accent)]" : "bg-[var(--border)]"}`}>
            <span className={`absolute top-0.5 w-5 h-5 rounded-full bg-white transition-all ${prefs[k] ? "left-[22px]" : "left-0.5"}`} />
          </button>
        </div>
      ))}
    </div>
  );
}

